import React from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { useAuth } from './context/AuthContext';

// Layout Components
import Navbar from './components/Navbar';

// Page Nodes
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import GeneratePage from './pages/GeneratePage';
import PortfolioPage from './pages/PortfolioPage';

/**
 * 🛡️ Security Gate
 * Protects private strategy nodes and maintains middle alignment during loading.
 */
const ProtectedRoute = ({ children }) => {
  const { user, loading } = useAuth();
  const location = useLocation();

  if (loading) {
    return (
      <div className="min-h-screen bg-[#0a0a0a] flex flex-col items-center justify-center font-mono">
        <div className="w-12 h-1 bg-emerald-500/10 rounded-full overflow-hidden w-48">
          <div className="h-full bg-emerald-500 animate-[loading_2s_infinite]" style={{ width: '40%' }} />
        </div>
        <p className="text-emerald-500 text-[10px] tracking-[0.4em] mt-4 uppercase animate-pulse">
          authenticating_node...
        </p>
      </div>
    );
  }

  return user ? children : <Navigate to="/login" state={{ from: location }} replace />;
};

function App() {
  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-mono selection:bg-emerald-500 selection:text-black">
      {/* 🔔 Terminal Notifications */}
      <Toaster 
        position="bottom-right"
        toastOptions={{
          className: 'terminal-card',
          style: { 
            background: '#141414', 
            color: '#fff', 
            border: '1px solid rgba(16, 185, 129, 0.2)', 
            fontSize: '11px',
            borderRadius: '12px'
          },
        }} 
      />

      <Navbar />

      {/* 🏛️ Central Padding & Middle Alignment Container */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12 min-h-[calc(100vh-80px)] flex flex-col justify-start">
        <Routes>
          {/* Public Identity Nodes */}
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />

          {/* Secure Private Nodes */}
          <Route 
            path="/dashboard" 
            element={<ProtectedRoute><DashboardPage /></ProtectedRoute>} 
          />
          <Route 
            path="/generate" 
            element={<ProtectedRoute><GeneratePage /></ProtectedRoute>} 
          />
          <Route 
            path="/portfolio/:id" 
            element={<ProtectedRoute><PortfolioPage /></ProtectedRoute>} 
          />

          {/* Fallback Redirection */}
          <Route path="/" element={<Navigate to="/dashboard" replace />} />
          <Route path="*" element={<Navigate to="/dashboard" replace />} />
        </Routes>
      </main>

      {/* Background Texture (CRT Scanlines) */}
      <div className="fixed inset-0 pointer-events-none z-[9999] opacity-[0.02] bg-[linear-gradient(rgba(18,16,16,0)_50%,rgba(0,0,0,0.25)_50%),linear-gradient(90deg,rgba(255,0,0,0.06),rgba(0,255,0,0.02),rgba(0,0,255,0.06))] bg-[length:100%_2px,3px_100%]" />
    </div>
  );
}

export default App;
